  property(round_trip format∘parse) →
  consumer_contract(δ1,δ2,δ3) →
  snapshot(pre_extract vs post_extract) ∧ ci(workspace_build)

V: diff(call_sites)==∅ ∧ golden_parity ∧ all_consumers_green
R: ! locale_drift ∧ ! rounding_divergence ∧
